//! Dispatch for `Expression::ExtraBuiltinFunctionCall` — layout helper
//! functions generated by the LLR's layout lowering pass.

use crate::Value;
use crate::eval::{EvalContext, eval_expression};
use i_slint_compiler::llr::Expression;
use i_slint_core::SharedVector;
use i_slint_core::items::LayoutAlignment;
use i_slint_core::layout::{
    BoxLayoutData, FlexboxLayoutData, FlexboxLayoutItemInfo, GridLayoutData, GridLayoutInputData,
    LayoutInfo, LayoutItemInfo, Padding,
};
use i_slint_core::model::Model;
use i_slint_core::slice::Slice;

// ── Value → layout-type converters ──────────────────────────────────────────

fn to_f32(v: &Value) -> f32 {
    match v {
        Value::Number(n) => *n as f32,
        _ => 0.,
    }
}

fn to_padding(v: &Value) -> Padding {
    let Value::Struct(s) = v else { return Padding::default() };
    let f = |k| match s.get_field(k) {
        Some(Value::Number(n)) => *n as f32,
        _ => 0.,
    };
    Padding { begin: f("begin"), end: f("end") }
}

fn to_alignment(v: &Value) -> LayoutAlignment {
    match v {
        Value::EnumerationValue(_, n) => n.parse().unwrap_or_default(),
        _ => LayoutAlignment::default(),
    }
}

fn to_orientation(v: &Value) -> i_slint_core::items::Orientation {
    match v {
        Value::EnumerationValue(_, n) => n.parse().unwrap_or_default(),
        _ => Default::default(),
    }
}

fn to_enum<T: std::str::FromStr + Default>(v: &Value) -> T {
    match v {
        Value::EnumerationValue(_, n) => n.parse().unwrap_or_default(),
        _ => T::default(),
    }
}

fn to_cells(v: &Value) -> Vec<LayoutItemInfo> {
    let Value::Model(m) = v else { return Vec::new() };
    (0..m.row_count())
        .filter_map(|i| {
            let Value::Struct(s) = m.row_data(i)? else { return None };
            let c = s.get_field("constraint")?;
            Some(LayoutItemInfo { constraint: c.clone().try_into().unwrap_or_default() })
        })
        .collect()
}

fn to_flex_cells(v: &Value) -> Vec<FlexboxLayoutItemInfo> {
    use i_slint_core::items::FlexboxLayoutAlignSelf;
    let Value::Model(m) = v else { return Vec::new() };
    (0..m.row_count())
        .filter_map(|i| {
            let Value::Struct(s) = m.row_data(i)? else { return None };
            let constraint: LayoutInfo = s
                .get_field("constraint")
                .cloned()
                .and_then(|v| v.try_into().ok())
                .unwrap_or_default();
            let f = |k1: &str, k2: &str| -> f32 {
                match s.get_field(k1).or_else(|| s.get_field(k2)) {
                    Some(Value::Number(n)) => *n as f32,
                    _ => 0.,
                }
            };
            let flex_basis = f("flex-basis", "flex_basis");
            Some(FlexboxLayoutItemInfo {
                constraint,
                flex_grow: f("flex-grow", "flex_grow"),
                flex_shrink: f("flex-shrink", "flex_shrink"),
                flex_basis: if flex_basis == 0. { -1. } else { flex_basis },
                flex_align_self: match s
                    .get_field("flex-align-self")
                    .or_else(|| s.get_field("flex_align_self"))
                {
                    Some(Value::EnumerationValue(_, n)) => n.parse().unwrap_or_default(),
                    _ => FlexboxLayoutAlignSelf::default(),
                },
                flex_order: match s.get_field("flex-order").or_else(|| s.get_field("flex_order")) {
                    Some(Value::Number(n)) => *n as i32,
                    _ => 0,
                },
            })
        })
        .collect()
}

fn to_u32_vec(v: &Value) -> Vec<u32> {
    let Value::Model(m) = v else { return Vec::new() };
    (0..m.row_count())
        .filter_map(|i| match m.row_data(i)? {
            Value::Number(n) => Some(n as u32),
            _ => None,
        })
        .collect()
}

fn to_grid_input_data(v: &Value) -> Vec<GridLayoutInputData> {
    let Value::Model(m) = v else { return Vec::new() };
    (0..m.row_count())
        .filter_map(|i| {
            let Value::Struct(s) = m.row_data(i)? else { return None };
            let f = |k: &str| match s.get_field(k) {
                Some(Value::Number(n)) => *n as f32,
                _ => 0.,
            };
            Some(GridLayoutInputData {
                new_row: matches!(s.get_field("new_row"), Some(Value::Bool(true))),
                col: f("col"),
                row: f("row"),
                colspan: f("colspan"),
                rowspan: f("rowspan"),
            })
        })
        .collect()
}

fn to_array_of_u16(v: &Value) -> SharedVector<u16> {
    match v {
        Value::ArrayOfU16(v) => v.clone(),
        _ => Default::default(),
    }
}

fn to_dialog_roles(v: &Value) -> Vec<i_slint_core::items::DialogButtonRole> {
    let Value::Model(m) = v else { return Vec::new() };
    (0..m.row_count())
        .filter_map(|i| match m.row_data(i)? {
            Value::EnumerationValue(_, n) => n.parse().ok(),
            _ => None,
        })
        .collect()
}

fn sf32(s: &crate::api::Struct, k: &str) -> f32 {
    match s.get_field(k) {
        Some(Value::Number(n)) => *n as f32,
        _ => 0.,
    }
}

// ── Dispatch ────────────────────────────────────────────────────────────────

pub(crate) fn call_extra_builtin(
    ctx: &mut EvalContext,
    name: &str,
    arguments: &[Expression],
) -> Value {
    let a: Vec<Value> = arguments.iter().map(|e| eval_expression(ctx, e)).collect();

    match name {
        "box_layout_info" => {
            let c = to_cells(&a[0]);
            i_slint_core::layout::box_layout_info(
                Slice::from_slice(&c),
                to_f32(&a[1]),
                &to_padding(&a[2]),
                to_alignment(&a[3]),
            )
            .into()
        }
        "box_layout_info_ortho" => {
            let c = to_cells(&a[0]);
            i_slint_core::layout::box_layout_info_ortho(Slice::from_slice(&c), &to_padding(&a[1]))
                .into()
        }
        "organize_dialog_button_layout" => {
            let input = to_grid_input_data(&a[0]);
            let roles = to_dialog_roles(&a[1]);
            Value::ArrayOfU16(i_slint_core::layout::organize_dialog_button_layout(
                Slice::from_slice(&input),
                Slice::from_slice(&roles),
            ))
        }
        "organize_grid_layout" => {
            let (input, ri, rs) = (to_grid_input_data(&a[0]), to_u32_vec(&a[1]), to_u32_vec(&a[2]));
            Value::ArrayOfU16(i_slint_core::layout::organize_grid_layout(
                Slice::from_slice(&input),
                Slice::from_slice(&ri),
                Slice::from_slice(&rs),
            ))
        }
        "grid_layout_info" => {
            let (c, ri, rs) = (to_cells(&a[1]), to_u32_vec(&a[2]), to_u32_vec(&a[3]));
            i_slint_core::layout::grid_layout_info(
                to_array_of_u16(&a[0]),
                Slice::from_slice(&c),
                Slice::from_slice(&ri),
                Slice::from_slice(&rs),
                to_f32(&a[4]),
                &to_padding(&a[5]),
                to_orientation(&a[6]),
            )
            .into()
        }
        "solve_grid_layout" => {
            let (c, ri, rs) = (to_cells(&a[1]), to_u32_vec(&a[3]), to_u32_vec(&a[4]));
            let Value::Struct(s) = &a[0] else { return Value::LayoutCache(Default::default()) };
            Value::LayoutCache(i_slint_core::layout::solve_grid_layout(
                &GridLayoutData {
                    size: sf32(s, "size"),
                    spacing: sf32(s, "spacing"),
                    padding: s.get_field("padding").map(to_padding).unwrap_or_default(),
                    organized_data: s
                        .get_field("organized_data")
                        .map(to_array_of_u16)
                        .unwrap_or_default(),
                },
                Slice::from_slice(&c),
                to_orientation(&a[2]),
                Slice::from_slice(&ri),
                Slice::from_slice(&rs),
            ))
        }
        "solve_box_layout" => {
            let ri = to_u32_vec(&a[1]);
            let Value::Struct(s) = &a[0] else { return Value::LayoutCache(Default::default()) };
            let cells = s.get_field("cells").map(to_cells).unwrap_or_default();
            Value::LayoutCache(i_slint_core::layout::solve_box_layout(
                &BoxLayoutData {
                    size: sf32(s, "size"),
                    spacing: sf32(s, "spacing"),
                    padding: s.get_field("padding").map(to_padding).unwrap_or_default(),
                    alignment: s.get_field("alignment").map(to_alignment).unwrap_or_default(),
                    cells: Slice::from_slice(&cells),
                },
                Slice::from_slice(&ri),
            ))
        }
        "solve_flexbox_layout" => {
            let ri = to_u32_vec(&a[1]);
            let Value::Struct(s) = &a[0] else { return Value::LayoutCache(Default::default()) };
            let (ch, cv) = (
                s.get_field("cells_h").map(to_flex_cells).unwrap_or_default(),
                s.get_field("cells_v").map(to_flex_cells).unwrap_or_default(),
            );
            Value::LayoutCache(i_slint_core::layout::solve_flexbox_layout(
                &FlexboxLayoutData {
                    width: sf32(s, "width"),
                    height: sf32(s, "height"),
                    spacing_h: sf32(s, "spacing_h"),
                    spacing_v: sf32(s, "spacing_v"),
                    padding_h: s.get_field("padding_h").map(to_padding).unwrap_or_default(),
                    padding_v: s.get_field("padding_v").map(to_padding).unwrap_or_default(),
                    alignment: s.get_field("alignment").map(to_alignment).unwrap_or_default(),
                    direction: s.get_field("direction").map(|v| to_enum(v)).unwrap_or_default(),
                    align_content: s
                        .get_field("align_content")
                        .map(|v| to_enum(v))
                        .unwrap_or_default(),
                    align_items: s.get_field("align_items").map(|v| to_enum(v)).unwrap_or_default(),
                    flex_wrap: s.get_field("flex_wrap").map(|v| to_enum(v)).unwrap_or_default(),
                    cells_h: Slice::from_slice(&ch),
                    cells_v: Slice::from_slice(&cv),
                },
                Slice::from_slice(&ri),
            ))
        }
        "flexbox_layout_info" => {
            let (ch, cv) = (to_flex_cells(&a[0]), to_flex_cells(&a[1]));
            i_slint_core::layout::flexbox_layout_info(
                Slice::from_slice(&ch),
                Slice::from_slice(&cv),
                to_f32(&a[2]),
                to_f32(&a[3]),
                &to_padding(&a[4]),
                &to_padding(&a[5]),
                to_orientation(&a[6]),
                to_enum(&a[7]),
                to_f32(&a[8]),
                to_enum(&a[9]),
            )
            .into()
        }
        other => unimplemented!("ExtraBuiltinFunctionCall `{other}`"),
    }
}
